import{_ as t}from"./chunks/ue-blueprint-sidebar.DWFzsi19.js";import{_ as a}from"./chunks/floatingball.D-BT0bmL.js";import{_ as i,o as n,c as r,ag as l}from"./chunks/framework.BqfgOMAh.js";const f=JSON.parse('{"title":"Overview","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/overview.md","filePath":"en/guide/overview.md"}'),o={name:"en/guide/overview.md"};function s(d,e,p,u,c,h){return n(),r("div",null,[...e[0]||(e[0]=[l('<h1 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h1><h2 id="what-is-nexusflow" tabindex="-1">What is NexusFlow? <a class="header-anchor" href="#what-is-nexusflow" aria-label="Permalink to &quot;What is NexusFlow?&quot;">​</a></h2><p>NexusFlow is an <strong>AI-powered Unreal Engine Blueprint assistant</strong>. It lets developers read, create, and edit UE Blueprints through natural language conversations — no need to memorize complex node names or workflows. Just describe what you want in plain language.</p><p>NexusFlow runs as a standalone desktop application on your computer and communicates with the Unreal Engine Editor in real time through a companion UE plugin. Starting with 0.2.0, the desktop app also includes an embedded MCP server so Cursor, Claude Code, and other external IDE agents can use the same UE automation capabilities.</p><p><img src="'+t+'" alt="NexusFlow working alongside UE Blueprint Editor"></p><h2 id="core-features" tabindex="-1">Core Features <a class="header-anchor" href="#core-features" aria-label="Permalink to &quot;Core Features&quot;">​</a></h2><h3 id="🤖-ai-chat" tabindex="-1">🤖 AI Chat <a class="header-anchor" href="#🤖-ai-chat" aria-label="Permalink to &quot;🤖 AI Chat&quot;">​</a></h3><p>Communicate with AI using natural language to describe your Blueprint operations:</p><ul><li>Read and explain Blueprint logic</li><li>Create new Blueprint nodes and connections</li><li>Modify existing Blueprint structure and properties</li><li>Manage Blueprint variables, functions, and events</li><li>Search and use UE Skills</li></ul><h3 id="🔮-floating-ball" tabindex="-1">🔮 Floating Ball <a class="header-anchor" href="#🔮-floating-ball" aria-label="Permalink to &quot;🔮 Floating Ball&quot;">​</a></h3><p><img src="'+a+`" alt="NexusFlow floating ball"></p><p>A quick-access entry point on your desktop — a blue-purple gradient circle icon:</p><ul><li>Click to open the AI chat sidebar</li><li>Drag to move; automatically snaps to the nearest screen edge</li><li>Show/hide via the system tray</li></ul><h3 id="💬-ai-chat-sidebar" tabindex="-1">💬 AI Chat Sidebar <a class="header-anchor" href="#💬-ai-chat-sidebar" aria-label="Permalink to &quot;💬 AI Chat Sidebar&quot;">​</a></h3><p>A feature-rich conversation interface:</p><ul><li>Three window modes: Floating, Dock Left, Dock Right</li><li>Real-time UE connection status and current model display</li><li>Tool call status tracking</li><li>Stop AI generation on demand</li></ul><h3 id="⚡-ue-quick-menu" tabindex="-1">⚡ UE Quick Menu <a class="header-anchor" href="#⚡-ue-quick-menu" aria-label="Permalink to &quot;⚡ UE Quick Menu&quot;">​</a></h3><p>Invoke AI directly from within the UE Editor through <strong>4 entry points</strong> with <strong>17 operations</strong>:</p><ul><li><strong>Blueprint Editor Right-Click</strong> — 13 operations (explain, optimize, extract, fix, document...)</li><li><strong>Content Browser Right-Click</strong> — Explain or document entire Blueprint assets</li><li><strong>Blueprint Editor Toolbar</strong> — Review and summarize the current Blueprint</li><li><strong>Level Editor Toolbar</strong> — NexusFlow button with connection status indicator</li><li>Smart filtering: menus adapt based on your node selection (none / single / multi)</li></ul><h3 id="🔌-mcp-server-and-external-ide-integration" tabindex="-1">🔌 MCP Server and External IDE Integration <a class="header-anchor" href="#🔌-mcp-server-and-external-ide-integration" aria-label="Permalink to &quot;🔌 MCP Server and External IDE Integration&quot;">​</a></h3><p>NexusFlow 0.2.0 can run as an MCP server, allowing MCP-capable IDEs and agents to use NexusFlow&#39;s Unreal Engine capabilities directly:</p><ul><li>Check the NexusFlow ↔ UE plugin connection</li><li>Inspect the current Unreal Editor context</li><li>Search and load NexusFlow Skills</li><li>Execute supported Blueprint, Widget, asset, and editor actions</li><li>Search Blueprint nodes and reuse templates</li></ul><p>The companion <code>nexusflow-skill</code> package provides portable instructions for AGENTS, Claude Code, and Cursor so external agents can follow the safe progressive workflow.</p><h3 id="🧪-widget-blueprint-skill-mvp" tabindex="-1">🧪 Widget Blueprint Skill MVP <a class="header-anchor" href="#🧪-widget-blueprint-skill-mvp" aria-label="Permalink to &quot;🧪 Widget Blueprint Skill MVP&quot;">​</a></h3><p>The experimental Widget Skill is now available for trying UMG Widget Blueprint creation and editing, including widget tree read/write, property-level patching, and real preview screenshot validation when available.</p><h3 id="⚙️-settings" tabindex="-1">⚙️ Settings <a class="header-anchor" href="#⚙️-settings" aria-label="Permalink to &quot;⚙️ Settings&quot;">​</a></h3><p>An iOS-style settings interface for managing all configurations:</p><ul><li>AI model management (multi-model switching)</li><li>Agent behavior parameters</li><li>Custom hotkeys</li><li>Appearance themes and language</li></ul><h3 id="🌐-multi-language-support" tabindex="-1">🌐 Multi-Language Support <a class="header-anchor" href="#🌐-multi-language-support" aria-label="Permalink to &quot;🌐 Multi-Language Support&quot;">​</a></h3><ul><li>Interface languages: Simplified Chinese, Traditional Chinese, English</li><li>AI response language can be set independently</li></ul><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>NexusFlow consists of three core components working together:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────┐    IPC Comm    ┌──────────────┐    FFI    ┌──────────────┐</span></span>
<span class="line"><span>│  Tauri Desktop   │ ◄───────────► │  Rust Bridge  │ ◄──────► │  UE Plugin    │</span></span>
<span class="line"><span>│  (React + Rust)  │               │  (Comm + Conv)│          │  (C++ + Py)   │</span></span>
<span class="line"><span>└─────────────────┘               └──────────────┘          └──────────────┘</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        │ SSE (Server-Sent Events)</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>  ┌──────────────┐</span></span>
<span class="line"><span>  │   LLM API    │</span></span>
<span class="line"><span>  │ (Cloud Model) │</span></span>
<span class="line"><span>  └──────────────┘</span></span></code></pre></div><ul><li><strong>Tauri Desktop App</strong>: Provides the AI chat interface (React frontend), LLM API proxy (Rust backend), and embedded MCP server</li><li><strong>Rust Bridge</strong>: Handles IPC communication between the desktop app and UE plugin, plus Blueprint data format conversion</li><li><strong>UE Plugin</strong>: Executes Blueprint operations within Unreal Engine and provides the Python Skills system</li></ul><h3 id="data-flow" tabindex="-1">Data Flow <a class="header-anchor" href="#data-flow" aria-label="Permalink to &quot;Data Flow&quot;">​</a></h3><p>When you send a message:</p><ol><li>The message is sent from the Tauri app to the LLM (e.g., GPT-5, Claude)</li><li>The LLM analyzes the request and determines which tools to call</li><li>Tool calls come from the desktop app or an external MCP client, then are forwarded through the Rust Bridge to the UE plugin</li><li>The UE plugin executes Blueprint operations (read, modify, create, etc.)</li><li>Results are returned along the same path, and the AI presents them in the conversation</li></ol><h2 id="supported-llm-providers" tabindex="-1">Supported LLM Providers <a class="header-anchor" href="#supported-llm-providers" aria-label="Permalink to &quot;Supported LLM Providers&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Provider</th><th>Description</th></tr></thead><tbody><tr><td><strong>OpenAI</strong></td><td>GPT series — strong general capabilities</td></tr><tr><td><strong>Anthropic</strong></td><td>Claude series — excellent reasoning ability</td></tr><tr><td><strong>Google Gemini</strong></td><td>Gemini series — multimodal support</td></tr><tr><td><strong>DeepSeek</strong></td><td>DeepSeek series — cost-effective</td></tr><tr><td><strong>Zhipu GLM</strong></td><td>GLM series — coding specialist</td></tr><tr><td><strong>MiniMax</strong></td><td>MiniMax series — excellent for agent workflows</td></tr><tr><td><strong>Qwen</strong></td><td>Qwen series — million-token context</td></tr><tr><td><strong>Kimi</strong></td><td>Kimi series — multimodal + coding</td></tr><tr><td><strong>Custom</strong></td><td>Any third-party API compatible with the above protocols</td></tr></tbody></table><p>You can configure multiple models simultaneously and switch the default model in Settings.</p><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="./getting-started">Quick Start</a> — Install and configure in 5 minutes</li><li><a href="./ai-chat">AI Chat</a> — Explore the chat interface in detail</li><li><a href="./blueprint-operations">Blueprint Operations</a> — Common conversation examples and detailed operations</li><li><a href="./mcp">Use NexusFlow from IDEs / Agents</a> — Use NexusFlow from Cursor, Claude Code, and other IDEs</li><li><a href="./widget-skill">Widget Skill</a> — Try UMG Widget Blueprint generation and editing</li></ul>`,42)])])}const b=i(o,[["render",s]]);export{f as __pageData,b as default};
